import{fetchAndDecrypt}from"./secure-content.js";const API_BASE="http://localhost:8080";function getToken(){return localStorage.getItem("jwt")||""}export async function loadEncryptedContent(){const t=getToken();if(!t)throw new Error("no_token_in_storage");const e=await fetch(`${API_BASE}/api/content/latest`,{headers:{Authorization:`Bearer ${t}`}}).then(t=>{if(!t.ok)throw new Error("latest_failed");return t.json()});if(!e.key_base64_dev)throw new Error("no_dev_key");const n=await fetchAndDecrypt({token:t,url:API_BASE+e.url,keyBase64:e.key_base64_dev});return window.__CITY_DATA__=n,{meta:e,data:n}}window.addEventListener("DOMContentLoaded",async()=>{try{const{data:t}=await loadEncryptedContent()}catch(t){console.warn("loadEncryptedContent failed:",t.message)}});